using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2019-09-01") },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2017-09-01") },
                new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2018-09-01") },
                new Student { ID = 4, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = DateTime.Parse("2017-09-01") },
                new Student { ID = 5, LastName = "Li", FirstMidName = "Yan", EnrollmentDate = DateTime.Parse("2017-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") },
                new Department { DepartmentID = 3, Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor
                {
                    ID = 10,
                    LastName = "Kapoor",
                    FirstMidName = "Candace",
                    HireDate = DateTime.Parse("2001-01-15"),
                    CourseAssignments = new List<CourseAssignment>(),
                    OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
                },
                new Instructor
                {
                    ID = 11,
                    LastName = "Fakhouri",
                    FirstMidName = "Fadi",
                    HireDate = DateTime.Parse("2002-07-06"),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2 }
            );
            context.SaveChanges();
        }

        public static void SeedAll(SchoolContext context)
        {
            SeedDepartments(context);
            SeedInstructors(context);
            SeedCourses(context);
            SeedStudents(context);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            using var service = new NotificationService();

            service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            using var service = new NotificationService();

            service.SendNotification("Department", "1", "Math", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            using var service = new NotificationService();

            // Drain the queue first
            while (service.ReceiveNotification() != null) { }

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "Jane Doe", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.Equal("New Student 'Jane Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            using var service = new NotificationService();

            service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var notification = service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            using var service = new NotificationService();

            service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

            var notification = service.ReceiveNotification();
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtTimestamp()
        {
            using var service = new NotificationService();
            var before = System.DateTime.Now;

            service.SendNotification("Student", "5", "Test", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= System.DateTime.Now);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            using var service = new NotificationService();
            // Should not throw for the in-memory implementation
            service.MarkAsRead(1);
            service.MarkAsRead(999);
        }

        [Fact]
        public void SendNotification_MultipleMessages_MaintainsOrder()
        {
            using var service = new NotificationService();

            service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            service.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);
            service.SendNotification("Student", "3", "Third", EntityOperation.DELETE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();
            var third = service.ReceiveNotification();

            Assert.Contains("First", first.Message);
            Assert.Contains("Second", second.Message);
            Assert.Contains("Third", third.Message);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            service.Dispose(); // Should not throw
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(5, result.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 5, 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 50).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatesCorrectly_ExactDivision()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_CalculatesCorrectly_WithRemainder()
        {
            var source = Enumerable.Range(1, 31).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_SingleItem_OnePage()
        {
            var source = new[] { 42 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(result);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 30, 2, 10);

            Assert.Equal(3, list.Count);
            Assert.Equal(2, list.PageIndex);
            Assert.Equal(3, list.TotalPages);
        }
    }
}

using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(5, model.Count);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsDescendingOrder()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            // 2017 dates come first
            Assert.Equal(2017, model.First().EnrollmentDate.Year);
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(2019, model.First().EnrollmentDate.Year);
        }

        [Fact]
        public void Index_DefaultSort_ReturnsNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Li", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Li", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "A", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Li", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToDesc()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            // Add enrollment data for the student
            _context.Courses.Add(new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = 0 });
            _context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 100, StudentID = 1, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavestoDatabase()
        {
            var student = new Student
            {
                LastName = "Saved",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-05-01")
            };

            _controller.Create(student);

            Assert.Contains(_context.Students, s => s.LastName == "Saved");
        }

        [Fact]
        public void Create_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "NoLast",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        [Fact]
        public void Create_Post_DateBeforeSqlRange_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Old",
                FirstMidName = "Very",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsStudent()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Updated",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2019-09-01")
            };

            // Detach existing tracked entity
            var existing = _context.Students.Find(1);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2019-09-01")
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsStudent()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Students.Find(1));
        }

        #endregion
    }
}

