            var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var filePath = Path.Combine(uploadsPath, "test_image.jpg");
            File.WriteAllText(filePath, "fake image");

            var course = _context.Courses.Find(4022);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(4022);

            Assert.False(File.Exists(filePath));
        }

        #endregion

        private Mock<IFormFile> CreateMockFormFile(string fileName, string content, long length)
        {
            var fileMock = new Mock<IFormFile>();
            var stream = new MemoryStream(Encoding.UTF8.GetBytes(content));
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return fileMock;
        }
    }
}

