using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsDepartment()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", dept.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesToDatabase()
        {
            var dept = new Department
            {
                Name = "Art",
                Budget = 50000,
                StartDate = DateTime.Parse("2021-06-01")
            };

            _controller.Create(dept);

            Assert.Contains(_context.Departments, d => d.Name == "Art");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { Budget = 100000, StartDate = DateTime.Now };

            var result = _controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", dept.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English Updated",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01"),
                RowVersion = new byte[] { 0 }
            };

            var existing = _context.Departments.Find(1);
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                DepartmentID = 1,
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };

            var result = _controller.Edit(dept) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsDepartment()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("English", dept.Name);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Departments.Find(1));
        }

        #endregion
    }
}

