using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedCourses(_context);
            TestHelpers.SeedInstructors(_context);

            // Add course assignments
            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 10, CourseID = 1050 });
            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 10, CourseID = 4022 });
            _context.SaveChanges();

            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var result = _controller.Index(10, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Equal(2, model.Courses.Count());
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            // Add an enrollment for course 1050
            _context.Students.Add(new Student
            {
                ID = 100,
                LastName = "TestStudent",
                FirstMidName = "X",
                EnrollmentDate = DateTime.Now
            });
            _context.SaveChanges();

            var course = _context.Courses.Include(c => c.Enrollments).First(c => c.CourseID == 1050);
            _context.Enrollments.Add(new Enrollment { CourseID = 1050, StudentID = 100, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Index(10, 1050) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_SetsViewBagInstructorID()
        {
            _controller.Index(10, null);

            Assert.Equal(10, _controller.ViewBag.InstructorID);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kapoor", instructor.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithCourseData()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "Multi",
                HireDate = DateTime.Parse("2020-01-01")
            };
            var selectedCourses = new[] { "1050", "4022" };

            _controller.Create(instructor, selectedCourses);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.LastName == "CourseInstructor");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "NoLast",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsInstructorWithCourses()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kapoor", instructor.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsInstructor()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kapoor", instructor.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _controller.DeleteConfirmed(11) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Instructors.Find(11));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Assign instructor 10 as department administrator
            var dept = _context.Departments.Find(1);
            dept.InstructorID = 10;
            _context.SaveChanges();

            _controller.DeleteConfirmed(10);

            var updatedDept = _context.Departments.Find(1);
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

