using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirst()
        {
            var student = new Student { LastName = "Smith", FirstMidName = "John" };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_IsRequired()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = default
            };

            var results = ValidateModel(student);
            // DateTime defaults to MinValue which is outside Range attribute
            Assert.Contains(results, r => r.MemberNames.Contains("EnrollmentDate"));
        }

        [Fact]
        public void Student_LastName_Required()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Now
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstMidName_Required()
        {
            var student = new Student
            {
                LastName = "Test",
                EnrollmentDate = DateTime.Now
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastName_MaxLength50()
        {
            var student = new Student
            {
                LastName = new string('a', 51),
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Instructor_HireDate_IsRequired()
        {
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "User",
                HireDate = default
            };

            var results = ValidateModel(instructor);
            Assert.Contains(results, r => r.MemberNames.Contains("HireDate"));
        }

        [Fact]
        public void Instructor_FullName_ReturnsCorrectFormat()
        {
            var instructor = new Instructor { LastName = "Kapoor", FirstMidName = "Candace" };

            Assert.Equal("Kapoor, Candace", instructor.FullName);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Title_MinLength3()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Title_MaxLength50()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = new string('a', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_Credits_RangeBetween0And5()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_Credits_NegativeIsInvalid()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Valid Title",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_ValidModel_NoErrors()
        {
            var course = new Course
            {
                CourseID = 1,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Name_MinLength3()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 100000,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_Name_MaxLength50()
        {
            var dept = new Department
            {
                Name = new string('a', 51),
                Budget = 100000,
                StartDate = DateTime.Now
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            var results = ValidateModel(enrollment);
            Assert.Empty(results);
        }

        [Fact]
        public void Enrollment_Grade_AllValuesValid()
        {
            foreach (Grade grade in Enum.GetValues(typeof(Grade)))
            {
                var enrollment = new Enrollment
                {
                    EnrollmentID = 1,
                    CourseID = 1,
                    StudentID = 1,
                    Grade = grade
                };

                var results = ValidateModel(enrollment);
                Assert.Empty(results);
            }
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_EntityType_Required()
        {
            var notification = new Notification
            {
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
        }

        [Fact]
        public void Notification_IsRead_DefaultsFalse()
        {
            var notification = new Notification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void Notification_ReadAt_CanBeNull()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now
            };

            Assert.Null(notification.ReadAt);
            var results = ValidateModel(notification);
            Assert.Empty(results);
        }

        #endregion

        #region ViewModels

        [Fact]
        public void AssignedCourseData_Properties()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2020-01-01"),
                StudentCount = 5
            };

            Assert.Equal(DateTime.Parse("2020-01-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void InstructorIndexData_Properties()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_Location_MaxLength50()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('a', 51)
            };

            var results = ValidateModel(oa);
            Assert.Contains(results, r => r.MemberNames.Contains("Location"));
        }

        [Fact]
        public void OfficeAssignment_ValidLocation_NoErrors()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Room 101"
            };

            var results = ValidateModel(oa);
            Assert.Empty(results);
        }

        #endregion

        #region EntityOperation Enum

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        private static IList<ValidationResult> ValidateModel(object model)
        {
